package arch.day2;

/**
 * Day 2 basic: static tables for primitives vs wrappers (conceptual).
 * // Spring services still map these types to JDBC and JSON every day.
 */
public class Day2Basic {

    public static void main(String[] args) {
        System.out.println("=== Eight primitives (width + default field value) ===");
        System.out.println("byte    8-bit   default 0");
        System.out.println("short   16-bit  default 0");
        System.out.println("int     32-bit  default 0");
        System.out.println("long    64-bit  default 0L");
        System.out.println("float   32-bit  IEEE  default 0.0f");
        System.out.println("double  64-bit  IEEE  default 0.0d");
        System.out.println("char    16-bit  UTF-16 unit  default \\u0000");
        System.out.println("boolean JVM-specific           default false");
        System.out.println();
        System.out.println("--- note: locals have no default; fields of these types do ---");
        System.out.println();
        System.out.println("=== Wrapper highlights ===");
        System.out.println("Integer can be null; int cannot — unboxing NPE is real.");
        System.out.println("List<int> illegal; List<Integer> required for generics.");
        System.out.println("Prefer Integer.valueOf over new Integer in modern code.");
        System.out.println();
        System.out.println("=== Literal suffixes ===");
        System.out.println("long literal needs L: 3_000_000_000L");
        System.out.println("float literal needs f: 1.5f");
        System.out.println("double default: 1.5 or 1.5d");
        System.out.println("underscores ok: 1_000_000");
        System.out.println();
        System.out.println("=== Sample locals (deterministic) ===");
        int units = 1_024;
        long bytes = units * 4L;
        double ratio = units / (double) 10_000;
        boolean on = true;
        char marker = 'Z';
        System.out.println("units=" + units + " bytes=" + bytes);
        System.out.println("ratio=" + ratio + " on=" + on + " marker=" + marker);
        System.out.println("done");
    }
}

package arch.day2;

import java.math.BigDecimal;

/**
 * Day 2 intermediate: four labelled scenarios, deterministic println only.
 * // Each scenario mirrors a code-review comment you might write on a junior PR.
 */
public class Day2Intermediate {

    static void divider(String label) {
        System.out.println("########################################");
        System.out.println("# " + label);
        System.out.println("########################################");
    }

    static void scenario1() {
        divider("Scenario 1: happy widening path");
        System.out.println("--- Scenario 1: happy widening path ---");
        int daily = 900_000;
        long annual = daily * 365L;
        double approx = daily;
        System.out.println("daily int=" + daily + " annual long=" + annual);
        System.out.println("widened to double=" + approx);
        System.out.println("note: multiply used 365L so product stays in long range");
        System.out.println();
    }

    static void scenario2() {
        divider("Scenario 2: narrowing to byte");
        System.out.println("--- Scenario 2: narrowing byte from int 300 ---");
        int big = 300;
        byte narrow = (byte) big;
        System.out.println("int value=" + big + " (byte) -> " + narrow);
        System.out.println("why: only low 8 bits kept; no exception thrown");
        System.out.println("review action: grep for (byte) casts in money or id paths");
        System.out.println();
    }

    static void scenario3() {
        divider("Scenario 3: Integer equality");
        System.out.println("--- Scenario 3: Integer == trap outside cache ---");
        Integer a = Integer.valueOf(200);
        Integer b = Integer.valueOf(200);
        System.out.println("a.equals(b)=" + a.equals(b));
        System.out.println("a == b (values 200)=" + (a == b));
        System.out.println("fix: compare primitives or use equals / Objects.equals");
        System.out.println("cache trivia: -128..127 often interned; do not rely on it");
        System.out.println();
    }

    static void scenario4() {
        divider("Scenario 4: decimal sums");
        System.out.println("--- Scenario 4: double versus BigDecimal for cents ---");
        double d = 0.1 + 0.2;
        BigDecimal bd = new BigDecimal("0.1").add(new BigDecimal("0.2"));
        System.out.println("double sum=" + d);
        System.out.println("BigDecimal sum=" + bd.toPlainString());
        System.out.println("money rule: BigDecimal + string ctor + explicit scale in real code");
        System.out.println("never use double for tax lines or invoice totals");
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("Day2Intermediate — four production-flavoured traces");
        System.out.println();
        scenario1();
        scenario2();
        scenario3();
        scenario4();
        System.out.println("all scenarios complete");
    }
}

package arch.day2;

import java.util.LinkedHashMap;
import java.util.Map;

/**
 * Day 2 advanced: deterministic widening/narrowing demo (assignment-aligned).
 * // Frameworks still boil down to these casts at DTO boundaries.
 */
public class Day2Advanced {

    static void printConversionTable(int x) {
        long asLong = x;
        double asDouble = x;
        short asShort = (short) x;
        byte asByte = (byte) x;
        System.out.println("source int: " + x);
        System.out.println("long:   " + asLong + "   (implicit widen)");
        System.out.println("double: " + asDouble + " (implicit widen)");
        System.out.println("short:  " + asShort + " (explicit narrow)");
        System.out.println("byte:   " + asByte + " (explicit narrow)");
    }

    static void printNarrowingLegend() {
        System.out.println("legend: narrowing never throws; validate ranges upstream");
    }

    static void printTriageTable() {
        System.out.println("symptom                         | first check");
        System.out.println("--------------------------------|----------------------------");
        System.out.println("random small positives in logs  | narrowing cast from long");
        System.out.println("negative dashboard totals       | int counter overflow");
        System.out.println("off-by-cent reconciliation      | double in money path");
        System.out.println("NPE in pricing                  | null Integer unbox");
    }

    public static void main(String[] args) {
        System.out.println("Day2Advanced start");
        System.out.println("=== Block 1: assignment value 1_000_000 ===");
        printConversionTable(1_000_000);
        printNarrowingLegend();
        System.out.println();

        System.out.println("=== Block 2: overflow guard pattern ===");
        int a = 2_000_000_000;
        int b = 2_000_000_000;
        System.out.println("operands a=" + a + " b=" + b);
        try {
            int bad = Math.addExact(a, b);
            System.out.println("unexpected sum=" + bad);
        } catch (ArithmeticException ex) {
            System.out.println("addExact caught overflow for int + int");
        }
        long good = (long) a + (long) b;
        System.out.println("promoted sum long=" + good);
        System.out.println("plain int add would wrap silently — avoid for money and metrics");
        System.out.println();

        System.out.println("=== Block 3: banking field decision matrix ===");
        Map<String, String> row = new LinkedHashMap<>();
        row.put("balance", "BigDecimal + string ctor + RoundingMode in prod");
        row.put("tx/day", "int ok; use long if lifetime totals");
        row.put("name", "String");
        row.put("active", "boolean (watch null vs tri-state)");
        row.put("acctId", "long if values exceed int");
        for (Map.Entry<String, String> e : row.entrySet()) {
            System.out.println(e.getKey() + " -> " + e.getValue());
        }
        System.out.println();
        System.out.println("=== Bonus triage table (on-call voice) ===");
        printTriageTable();
        System.out.println();
        System.out.println("reminder: promote to long before multiply when counts can grow");
        System.out.println("reminder: BigDecimal uses string ctor to avoid double pollution");
        System.out.println("reminder: compare boxed values with equals, not ==");
        System.out.println("reminder: document JSON id encoding for browser clients");
        System.out.println("reminder: run golden tests on any change to numeric DTO fields");
        System.out.println("Day2Advanced end");
    }
}

