package arch.day2;

/**
 * Day 2 exercise — primitives recap, narrowing demo, banking types, widen/narrow trace.
 * Complexity: O(1) time and O(1) space (scalar operations only).
 */
public class Day2Exercise {

    public static void main(String[] args) {
        System.out.println("1) Primitives (width + pick rule)");
        System.out.println("byte    8b  compact arrays/protocol fields");
        System.out.println("short  16b  seldom; prefer int unless measured");
        System.out.println("int    32b  default integral choice");
        System.out.println("long   64b  large counts, epoch millis, wide IDs");
        System.out.println("float  32b  graphics/ML features; not money");
        System.out.println("double 64b  scientific stats; not money");
        System.out.println("char   16b  single UTF-16 code unit");
        System.out.println("boolean    flags; not numeric");
        System.out.println();

        System.out.println("2) Narrowing int 300 -> byte");
        int wide = 300;
        byte narrow = (byte) wide;
        System.out.println("int=" + wide + " byte=" + narrow);
        System.out.println("explain: low 8 bits of 300 are 00101100 -> 44");
        System.out.println();

        System.out.println("3) Banking field picks");
        System.out.println("balance | BigDecimal | exact decimal ledger math");
        System.out.println("tx/day  | int        | safe if domain < 2^31-1; else long");
        System.out.println("name    | String     | textual data");
        System.out.println("active  | boolean    | two-state flag");
        System.out.println("acctId  | long       | exceeds int range comfortably");
        System.out.println();

        System.out.println("4) Widening and narrowing 1_000_000");
        int x = 1_000_000;
        long asLong = x;
        double asDouble = x;
        short asShort = (short) x;
        byte asByte = (byte) x;
        System.out.println("int:    " + x);
        System.out.println("long:   " + asLong);
        System.out.println("double: " + asDouble);
        System.out.println("short:  " + asShort + " (narrow)");
        System.out.println("byte:   " + asByte + " (narrow)");
    }
}

